def split_words(txt):
    '''
    Given a string of words, return a list of words separated by commas, if no commas exist in the text you
    should split on semicolons ';', if no semicolons are present you should return the total number of vowels 
    present regardless of case, ord('a') = 1, ord('e') = 2, ... ord('u') = 5
    Examples
    split_words("Hello world!") ➞ ["Hello world!"]
    split_words("Hello;world!") ➞ ["Hello;world!"]
    split_words("abcdef") == 4 
    '''
    if ',' in txt:
        return txt.split(',')
    elif ';' in txt:
        return txt.split(';')
    else:
        return sum(1 for char in txt if char.lower() in 'aeiou')
