def split_words(txt):
    '''
    Given a string of words, return a set of characters split on whitespace; if no whitespaces exist in the text you 
    should split on periods '.' if no periods exist you should return the number of upper-case letters with even order in the 
    alphabet, ord('A') = 1, ord('B') = 2, ... ord('Z') = 26
    Examples
    split_words("Hello world!") ➞ {"H", "e", "l", "o", " ", "w", "r", "l", "d", "!"}
    split_words("Hello.world!") ➞ {"H", "e", "l", "o", "world!"}
    split_words("abcdef") == 0 
    '''
    if ' ' in txt:
        return set(txt)  # Split on whitespace and return characters as a set
    elif '.' in txt:
        return txt.split('.')  # Split on periods if no whitespace
    else:
        # Count upper-case letters with even order in the alphabet
        return sum(1 for char in txt if char.isupper() and (ord(char) - ord('A')) % 2 == 0)
